{
  "terms": [
    {
      "term": "TN-S System",
      "simpleDefinition": "An earthing arrangement where the neutral and earth conductors are kept separate throughout the entire system from the substation to the installation.",
      "anchor": "Separate paths for earth and neutral from start to finish.",
      "misconception": "Learners often think a TN-S system requires an earth rod; it actually uses the metal sheath of the supplier's cable."
    },
    {
      "term": "TN-C-S System",
      "simpleDefinition": "An arrangement where the neutral and earth are combined in the supply cable but separated into two distinct terminals at the consumer's intake.",
      "anchor": "Combined in the street, split at the house.",
      "misconception": "Thinking the earth and neutral remain combined inside the consumer unit's final circuits."
    },
    {
      "term": "TT System",
      "simpleDefinition": "A system where the supplier does not provide an earth terminal, requiring the installation to be connected to a local earth electrode (rod).",
      "anchor": "Earth provided by a rod in the ground.",
      "misconception": "Assuming the supplier is legally required to provide an earth terminal for every property."
    },
    {
      "term": "ADS (Automatic Disconnection of Supply)",
      "simpleDefinition": "A safety measure that uses a low-resistance path to ensure a protective device trips quickly during a fault to prevent electric shock.",
      "anchor": "Fault occurs, path is found, power cuts off instantly.",
      "misconception": "Believing ADS only protects against circuit overloads rather than specifically protecting against electric shock during a fault."
    },
    {
      "term": "CPC (Circuit Protective Conductor)",
      "simpleDefinition": "The specific wire within a circuit that connects the metal parts of equipment to the main earthing terminal.",
      "anchor": "The green and yellow wire inside the cable.",
      "misconception": "Confusing the CPC with bonding conductors that connect to gas or water pipes."
    },
    {
      "term": "PEN Conductor",
      "simpleDefinition": "A single conductor that performs the functions of both a Protective Earth and a Neutral (used in TN-C-S supply cables).",
      "anchor": "One wire doing two jobs in the supply cable.",
      "misconception": "Thinking a PEN conductor is allowed to be used within the internal wiring of a domestic installation."
    },
    {
      "term": "Earth Electrode",
      "simpleDefinition": "A conductive part, such as a copper rod, driven into the soil to provide a physical connection to the mass of the Earth.",
      "anchor": "The copper-plated rod in the ground.",
      "misconception": "Thinking a rod provides a 'better' earth than a supplier's terminal; rods actually have much higher resistance."
    },
    {
      "term": "Protective Device",
      "simpleDefinition": "A component like a circuit breaker (MCB) or fuse designed to break the circuit when it detects a fault current.",
      "anchor": "The switch that trips or the fuse that blows.",
      "misconception": "Thinking a fuse 'slows down' the electricity rather than physically breaking the circuit."
    }
  ],
  "anchorPhrases": [
    "Separate paths for earth and neutral",
    "Combined in the street, split at the house",
    "Earth from a rod in the ground",
    "Fault occurs, path is found, power cuts off",
    "The green and yellow wire in the cable"
  ],
  "misconceptionTargets": [
    "The supplier always provides an earth terminal",
    "Earth and neutral stay combined inside the house",
    "ADS only protects against too many appliances being plugged in",
    "The CPC is the same as a bonding lead"
  ]
}

{
  "teachChecks": [
    {
      "title": "TN-S Earthing Arrangement",
      "basicQuestions": [
        {
          "questionText": "In the earthing code TN-S, what does the letter 'S' stand for?",
          "answerGuidance": [
            "Separate",
            "Separate paths",
            "Separated"
          ]
        },
        {
          "questionText": "In older TN-S installations, what part of the supplier's cable is the earth connection clamped to?",
          "answerGuidance": [
            "Lead sheath",
            "Metal sheath",
            "Cable armouring"
          ]
        },
        {
          "questionText": "What does the letter 'T' represent in the earthing system nomenclature?",
          "answerGuidance": [
            "Terre",
            "Earth",
            "Connection to Earth"
          ]
        }
      ],
      "deeperQuestionText": "Why is a TN-S system described as having a 'clean' earth compared to other arrangements?",
      "deeperAnswerGuidance": [
        "Earth and neutral conductors are distinct",
        "No mixing of neutral and earth currents",
        "Separate path from the substation to the installation",
        "Does not share a wire with the neutral return"
      ],
      "hint": "Think about the 'S' for 'Separate' paths from the substation to the house."
    },
    {
      "title": "TN-C-S Earthing Arrangement",
      "basicQuestions": [
        {
          "questionText": "What is the common UK name for a TN-C-S earthing arrangement?",
          "answerGuidance": [
            "PME",
            "Protective Multiple Earthing"
          ]
        },
        {
          "questionText": "What is the name of the single conductor that acts as both Neutral and Earth in the supplier's street cables?",
          "answerGuidance": [
            "PEN conductor",
            "Protective Earth and Neutral conductor"
          ]
        },
        {
          "questionText": "At what specific component is the combined supply conductor split into separate Earth and Neutral terminals?",
          "answerGuidance": [
            "Service head",
            "Cutout",
            "Supplier's cutout fuse"
          ]
        }
      ],
      "deeperQuestionText": "How does the function of the supply conductor change once it passes through the property's service head in a TN-C-S system?",
      "deeperAnswerGuidance": [
        "Transitions from combined to separate",
        "Splits into distinct earth and neutral terminals",
        "Becomes two separate conductors for the internal installation",
        "Stops acting as a PEN conductor"
      ],
      "hint": "Focus on where the 'Combined' path becomes 'Separate'—usually at the service head."
    },
    {
      "title": "TT Earthing Arrangement",
      "basicQuestions": [
        {
          "questionText": "What component must the installer provide for a TT system because the supplier does not provide an earth terminal?",
          "answerGuidance": [
            "Earth electrode",
            "Earth rod",
            "Copper-plated rod"
          ]
        },
        {
          "questionText": "Why is the resistance of the earth path much higher in a TT system than in a TN system?",
          "answerGuidance": [
            "Soil is a poor conductor",
            "High resistance of the ground",
            "Soil impedance"
          ]
        },
        {
          "questionText": "Which protective device is mandatory in a TT system to ensure the supply is cut off during a fault?",
          "answerGuidance": [
            "RCD",
            "Residual Current Device"
          ]
        }
      ],
      "deeperQuestionText": "Why is a standard circuit breaker (MCB) often insufficient on its own to provide ADS in a TT installation?",
      "deeperAnswerGuidance": [
        "High soil resistance limits fault current",
        "Fault current may be too low to trip the MCB instantly",
        "MCB requires high current to blow or trip",
        "RCD is needed to detect low-level leakage to earth"
      ],
      "hint": "Remember that 'TT' relies on the ground itself rather than a supplier's cable sheath."
    },
    {
      "title": "The Role of the CPC",
      "basicQuestions": [
        {
          "questionText": "What does the abbreviation CPC stand for in an electrical circuit?",
          "answerGuidance": [
            "Circuit Protective Conductor"
          ]
        },
        {
          "questionText": "What are the standard colors for the insulation of a CPC?",
          "answerGuidance": [
            "Green and yellow"
          ]
        },
        {
          "questionText": "To which specific terminal in the consumer unit does the CPC connect?",
          "answerGuidance": [
            "Main Earthing Terminal",
            "MET",
            "Earth bar"
          ]
        }
      ],
      "deeperQuestionText": "What is the safety consequence for a metal-clad appliance if its CPC is disconnected during a live-to-casing fault?",
      "deeperAnswerGuidance": [
        "The metal casing remains live",
        "No path for fault current to flow back to the source",
        "The protective device will not trip or blow",
        "Creates a high risk of electric shock to users"
      ],
      "hint": "The CPC is the internal circuit wire, not the main earthing conductor for the whole building."
    },
    {
      "title": "ADS and Protective Devices",
      "basicQuestions": [
        {
          "questionText": "What does the abbreviation ADS stand for?",
          "answerGuidance": [
            "Automatic Disconnection of Supply"
          ]
        },
        {
          "questionText": "What must be low in the earthing system to allow a massive surge of current to flow during a fault?",
          "answerGuidance": [
            "Resistance",
            "Impedance",
            "Earth path resistance"
          ]
        },
        {
          "questionText": "What is the typical maximum time allowed for a protective device to disconnect the supply during a fault to prevent fatal shock?",
          "answerGuidance": [
            "0.4 seconds",
            "Less than 0.4 seconds"
          ]
        }
      ],
      "deeperQuestionText": "How does the earthing system 'force' a fuse or circuit breaker to operate during a fault condition?",
      "deeperAnswerGuidance": [
        "Provides a low-resistance path for current",
        "Creates a massive surge of fault current",
        "The current exceeds the device's rating instantly",
        "Converts a dangerous fault into an overcurrent event"
      ],
      "hint": "ADS is the combination of a path for the current and a device that reacts to that current."
    }
  ]
}

